// Suporta: n8n webhook typeVersion 1 (body direto) e typeVersion 2 (body aninhado)
const raw = $input.first().json;
const payload = (raw.body && typeof raw.body === 'object' && raw.body !== null) ? raw.body : raw;

// Ignora eventos que nao sao mensagens recebidas
const event = payload.event || '';
if (event !== '' && event !== 'messages.upsert') return [];

const data = payload.data || {};
const key = data.key || {};
const msg = data.message || {};

// Extrai texto de todos os tipos de mensagem suportados
const text = (
  msg.conversation ||
  (msg.extendedTextMessage && msg.extendedTextMessage.text) ||
  (msg.imageMessage && msg.imageMessage.caption) ||
  (msg.videoMessage && msg.videoMessage.caption) ||
  (msg.documentMessage && msg.documentMessage.caption) ||
  ''
);

const remoteJid = key.remoteJid || '';
const fromMe = key.fromMe === true;
const instance = payload.instance || 'Teste';

// Filtra: mensagem propria, texto vazio, grupo
if (fromMe) return [];
if (!text.trim()) return [];
if (remoteJid.includes('@g.us')) return [];

const phone = remoteJid
  .replace('@s.whatsapp.net', '')
  .replace('@c.us', '');

return [{ json: { text: text.trim(), phone: phone, remoteJid: remoteJid, instance: instance } }];

const input = $input.first().json;
const text = (input.text || '').toLowerCase();
const now = new Date();

function fmt(d) { return d.toISOString().split('T')[0]; }
function addDays(n) {
  var d = new Date(now);
  d.setDate(d.getDate() + n);
  return fmt(d);
}

var dow = now.getDay();
var daysToMon = (dow === 0) ? 6 : (dow - 1);
var monday = new Date(now);
monday.setDate(now.getDate() - daysToMon);

var clientMap = [
  { keys: ['antonio neto', 'antonio'], id: 'act_497795903676192', nome: 'Antonio Neto' },
  { keys: ['gabriel jacinto', 'gabriel'], id: 'act_2493856707309984', nome: 'Gabriel Jacinto' },
  { keys: ['dani escudero', 'dani'], id: 'act_2145598605527232', nome: 'Dani Escudero' },
  { keys: ['agro'], id: 'act_929521557422139', nome: 'Agro' },
  { keys: ['escola de musica', 'escola de música', 'escola'], id: 'act_544347952854095', nome: 'Escola de Musica' },
  { keys: ['panmalhas'], id: 'act_1509005182799187', nome: 'Panmalhas' },
  { keys: ['gfix store', 'gfix'], id: 'act_2811791829124905', nome: 'GFiX Store' },
  { keys: ['arte em gelo', 'arte em'], id: 'act_5585082641598366', nome: 'Arte em Gelo' },
  { keys: ['itag tecnologia', 'itag'], id: 'act_738466861151636', nome: 'ITAG Tecnologia' },
  { keys: ['hi dogz', 'dogz'], id: 'act_873195821346004', nome: 'Hi Dogz' },
  { keys: ['batata bistro', 'batata bistrô', 'batata'], id: 'act_1673012226810411', nome: 'Batata Bistro' },
  { keys: ['caribbean bronze', 'caribbean'], id: 'act_1082397873705862', nome: 'Caribbean Bronze' },
  { keys: ['larissa kelleter', 'larissa'], id: 'act_738280412237298', nome: 'Larissa Kelleter' }
];

// Ordena por comprimento decrescente de chaves para priorizar matches mais especificos
clientMap.sort(function(a, b) {
  return b.keys[0].length - a.keys[0].length;
});

var isRelatorio = text.indexOf('relat') !== -1;

var clientFound = null;
for (var i = 0; i < clientMap.length; i++) {
  var entry = clientMap[i];
  for (var j = 0; j < entry.keys.length; j++) {
    if (text.indexOf(entry.keys[j]) !== -1) {
      clientFound = entry;
      break;
    }
  }
  if (clientFound) break;
}

var today = fmt(now);
var yesterday = addDays(-1);
var last7Start = addDays(-7);
var last7End = yesterday;
var isRelatorioWithClient = (isRelatorio && clientFound !== null);

return [{
  json: {
    text: input.text,
    phone: input.phone,
    remoteJid: input.remoteJid,
    instance: input.instance,
    today: today,
    yesterday: yesterday,
    weekStart: fmt(monday),
    last7: last7Start,
    last30: addDays(-30),
    last7Start: last7Start,
    last7End: last7End,
    metaToken: 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X',
    isRelatorio: isRelatorio,
    isRelatorioWithClient: isRelatorioWithClient,
    clientFound: clientFound ? clientFound.id : null,
    clientNome: clientFound ? clientFound.nome : null
  }
}];

const metaData = $input.first().json;
const ctx = $('Calcular Datas').first().json;
const campaigns = metaData.data || [];

function fmtMoney(val) {
  var n = parseFloat(val) || 0;
  var fixed = n.toFixed(2);
  var parts = fixed.split('.');
  parts[0] = parts[0].replace(/(\d)(?=(\d{3})+$)/g, '$1.');
  return parts[0] + ',' + parts[1];
}

function fmtNum(val) {
  var n = parseInt(val) || 0;
  return String(n).replace(/(\d)(?=(\d{3})+$)/g, '$1.');
}

function fmtBR(dateStr) {
  var d = new Date(dateStr + 'T12:00:00Z');
  return String(d.getUTCDate()).padStart(2, '0') + '/' + String(d.getUTCMonth() + 1).padStart(2, '0');
}

if (!campaigns.length) {
  return [{ json: {
    phone: ctx.phone,
    output: 'Sem dados de campanhas para *' + (ctx.clientNome || '').toUpperCase() + '* nos ultimos 7 dias.'
  } }];
}

var purchaseIds = ['act_873195821346004', 'act_1673012226810411'];
var isPurchase = purchaseIds.indexOf(ctx.clientFound) !== -1;

var totalSpend = 0;
var totalImpressions = 0;
var totalClicks = 0;

for (var i = 0; i < campaigns.length; i++) {
  totalSpend += parseFloat(campaigns[i].spend || '0');
  totalImpressions += parseInt(campaigns[i].impressions || '0');
  totalClicks += parseInt(campaigns[i].clicks || '0');
}

var clientUpper = (ctx.clientNome || '').toUpperCase();
var dateRange = '_\ud83d\udcc6 ' + fmtBR(ctx.last7Start) + ' a ' + fmtBR(ctx.last7End) + ' (ultimos 7 dias)_';
var reportText;

if (isPurchase) {
  var totalPurchases = 0;
  for (var i = 0; i < campaigns.length; i++) {
    var acts = campaigns[i].actions || [];
    for (var k = 0; k < acts.length; k++) {
      if (acts[k].action_type === 'purchase' || acts[k].action_type === 'offsite_conversion.fb_pixel_purchase') {
        totalPurchases += parseInt(acts[k].value) || 0;
      }
    }
  }
  var cpp = totalPurchases > 0 ? totalSpend / totalPurchases : 0;
  reportText =
    '*' + clientUpper + '*' + '\n\n' +
    dateRange + '\n\n' +
    '*Meta Ads*' + '\n\n' +
    'Impressoes: ' + fmtNum(totalImpressions) + '\n\n' +
    'Cliques: ' + fmtNum(totalClicks) + '\n\n' +
    'Vendas: ' + totalPurchases + '\n\n' +
    'Custo por venda: R$ ' + fmtMoney(cpp) + '\n\n' +
    '*INVESTIMENTO TOTAL: R$ ' + fmtMoney(totalSpend) + '*';
} else {
  var LEAD_TYPES = ['lead', 'onsite_conversion.lead_grouped', 'onsite_conversion.messaging_conversation_started_7d', 'onsite_conversion.total_messaging_connection'];
  var leadSpend = 0;
  var totalLeads = 0;
  for (var i = 0; i < campaigns.length; i++) {
    var acts = campaigns[i].actions || [];
    for (var k = 0; k < acts.length; k++) {
      if (LEAD_TYPES.indexOf(acts[k].action_type) !== -1) {
        leadSpend += parseFloat(campaigns[i].spend || '0');
        totalLeads += parseInt(acts[k].value) || 0;
        break;
      }
    }
  }
  var cpl = totalLeads > 0 ? leadSpend / totalLeads : 0;
  reportText =
    '*' + clientUpper + '*' + '\n\n' +
    dateRange + '\n\n' +
    '*Meta Ads*' + '\n\n' +
    'Impressoes: ' + fmtNum(totalImpressions) + '\n\n' +
    'Cliques: ' + fmtNum(totalClicks) + '\n\n' +
    'Leads: ' + totalLeads + '\n\n' +
    'Custo por lead: R$ ' + fmtMoney(cpl) + '\n\n' +
    '*INVESTIMENTO TOTAL: R$ ' + fmtMoney(totalSpend) + '*';
}

return [{ json: { phone: ctx.phone, output: reportText } }];

const metaResp = $input.first().json;
const ctx = $('Calcular Datas').first().json;
const allAccounts = metaResp.data || [];
const accountsList = allAccounts.map(function(a) {
  var status = a.account_status === 1 ? 'Ativa' : 'Inativa';
  return '- ' + a.name + ' | ID: ' + a.id + ' | ' + status;
}).join('\n') || 'Nenhuma conta encontrada';
return [{ json: {
  text: ctx.text,
  phone: ctx.phone,
  remoteJid: ctx.remoteJid,
  instance: ctx.instance,
  today: ctx.today,
  yesterday: ctx.yesterday,
  weekStart: ctx.weekStart,
  last7: ctx.last7,
  last30: ctx.last30,
  last7Start: ctx.last7Start,
  last7End: ctx.last7End,
  metaToken: ctx.metaToken,
  isRelatorio: ctx.isRelatorio,
  isRelatorioWithClient: ctx.isRelatorioWithClient,
  clientFound: ctx.clientFound,
  clientNome: ctx.clientNome,
  accounts: allAccounts,
  accountsList: accountsList
} }];

var params;
try { params = JSON.parse(query); } catch(e) { return 'Erro: JSON invalido. Envie object_id e date_preset'; }
var token = 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X';
var objectId = params.object_id;
var datePreset = params.date_preset || 'today';
var fields = params.fields || 'spend,impressions,clicks,ctr,cpc,actions,reach';
var level = params.level || '';
if (!objectId) return 'Erro: object_id obrigatorio';
var url = 'https://graph.facebook.com/v19.0/' + objectId + '/insights?date_preset=' + encodeURIComponent(datePreset) + '&fields=' + encodeURIComponent(fields) + '&access_token=' + token;
if (level) url += '&level=' + encodeURIComponent(level);
try {
  var res = await fetch(url);
  var data = await res.json();
  if (data.error) return 'Erro Meta: ' + data.error.message;
  if (!data.data || data.data.length === 0) return 'Sem dados para o periodo.';
  return JSON.stringify(data.data);
} catch(e) { return 'Erro conexao: ' + e.message; }

var params;
try { params = JSON.parse(query); } catch(e) { return 'Erro: envie JSON com account_id'; }
var token = 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X';
var accountId = params.account_id;
if (!accountId) return 'Erro: account_id obrigatorio';
try {
  var url = 'https://graph.facebook.com/v19.0/' + accountId + '/campaigns?fields=id,name,status,objective,daily_budget,lifetime_budget&limit=100&access_token=' + token;
  var res = await fetch(url);
  var data = await res.json();
  if (data.error) return 'Erro Meta: ' + data.error.message;
  if (!data.data || !data.data.length) return 'Nenhuma campanha encontrada';
  return JSON.stringify(data.data.map(function(c) {
    return { id: c.id, nome: c.name, status: c.status, objetivo: c.objective,
      budget_diario: c.daily_budget ? (parseInt(c.daily_budget)/100).toFixed(2) : null,
