  }));
} catch(e) { return 'Erro conexao: ' + e.message; }

var params;
try { params = JSON.parse(query); } catch(e) { return 'Erro: envie account_id ou campaign_id'; }
var token = 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X';
var baseId = params.campaign_id || params.account_id;
