var accountIds = params.account_ids || [];
var datePreset = params.date_preset || 'today';
var fields = params.fields || 'spend,impressions,clicks,actions,reach';
if (!accountIds.length) return 'Erro: account_ids vazio';
try {
  var results = [];
  for (var i = 0; i < accountIds.length; i++) {
    var url = 'https://graph.facebook.com/v19.0/' + accountIds[i] + '/insights?date_preset=' + encodeURIComponent(datePreset) + '&fields=' + encodeURIComponent(fields) + '&access_token=' + token;
    var res = await fetch(url);
    var data = await res.json();
    if (data.error) results.push({ account_id: accountIds[i], error: data.error.message });
    else if (data.data && data.data.length) results.push({ account_id: accountIds[i], data: data.data[0] });
    else results.push({ account_id: accountIds[i], data: null });
  }
  return JSON.stringify(results);
} catch(e) { return 'Erro conexao: ' + e.message; }
